const Redis = global.get('redis');
if (!Redis) {
    node.error('Redis client not available');
    return null;
}
const key = msg.payload.key;
const value = typeof msg.payload.value === 'object' 
    ? JSON.stringify(msg.payload.value) 
    : String(msg.payload.value || '');
const ttl = parseInt(msg.payload.ttl) || undefined;

if (!key) {
    node.warn('Missing Redis key');
    return null;
}

try {
    if (ttl) {
        await Redis.set(key, value, 'EX', ttl);
    } else {
        await Redis.set(key, value);
    }
    msg.payload = 'OK';
    return msg;
} catch(e) {
    node.error('Redis write error: ' + e.message);
    return null;
}
